<template><div><div class="page-title">巡检管理</div><el-tabs v-model="active"><el-tab-pane label="巡检计划" name="plans"><div class="page-card"><div class="toolbar"><el-input v-model="planQuery.planName" placeholder="计划名称" clearable style="width:180px"/><el-button type="primary" @click="loadPlans">查询</el-button><el-button type="success" @click="openPlan">新增计划</el-button></div><el-table :data="plans" border v-loading="planLoading"><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="planName" label="计划名称" min-width="180"/><el-table-column prop="deviceId" label="设备ID" width="100"/><el-table-column prop="inspectorId" label="巡检员ID" width="120"/><el-table-column prop="cycleType" label="周期" width="120"/><el-table-column label="状态" width="120"><template #default="{row}"><el-tag :type="Number(row.status)===1?'success':'info'">{{ Number(row.status)===1?'启用':'停用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="180"><template #default="{row}"><el-button size="small" type="warning" @click="changePlanStatus(row,0)">停用</el-button><el-button size="small" type="success" @click="changePlanStatus(row,1)">启用</el-button></template></el-table-column></el-table><el-pagination style="margin-top:16px" background layout="total, prev, pager, next, sizes" :total="planTotal" v-model:current-page="planQuery.pageNo" v-model:page-size="planQuery.pageSize" @current-change="loadPlans" @size-change="loadPlans"/></div></el-tab-pane><el-tab-pane label="巡检任务" name="tasks"><div class="page-card"><div class="toolbar"><el-input-number v-model="taskQuery.planId" placeholder="计划ID" :min="0"/><el-button type="primary" @click="loadTasks">查询</el-button></div><el-table :data="tasks" border v-loading="taskLoading"><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="planId" label="计划ID" width="100"/><el-table-column prop="deviceId" label="设备ID" width="100"/><el-table-column prop="inspectorId" label="巡检员ID" width="120"/><el-table-column label="状态" width="120"><template #default="{row}"><el-tag :type="taskStatusTag(row.status)">{{ taskStatusText(row.status) }}</el-tag></template></el-table-column><el-table-column prop="result" label="结果" width="120"/><el-table-column label="操作" width="220"><template #default="{row}"><el-button size="small" @click="startTask(row)">开始</el-button><el-button size="small" type="primary" @click="openSubmit(row)">提交</el-button></template></el-table-column></el-table><el-pagination style="margin-top:16px" background layout="total, prev, pager, next, sizes" :total="taskTotal" v-model:current-page="taskQuery.pageNo" v-model:page-size="taskQuery.pageSize" @current-change="loadTasks" @size-change="loadTasks"/></div></el-tab-pane></el-tabs><el-dialog v-model="planVisible" title="新增巡检计划" width="560px"><el-form :model="planForm" label-width="100px"><el-form-item label="计划名称"><el-input v-model="planForm.planName"/></el-form-item><el-form-item label="设备ID"><el-input-number v-model="planForm.deviceId" :min="1"/></el-form-item><el-form-item label="巡检员ID"><el-input-number v-model="planForm.inspectorId" :min="1"/></el-form-item><el-form-item label="周期"><el-input v-model="planForm.cycleType" placeholder="DAILY / WEEKLY / MONTHLY"/></el-form-item><el-form-item label="描述"><el-input v-model="planForm.description" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="planVisible=false">取消</el-button><el-button type="primary" @click="savePlan">保存</el-button></template></el-dialog><el-dialog v-model="submitVisible" title="提交巡检结果" width="460px"><el-form :model="submitForm" label-width="80px"><el-form-item label="结果"><el-input v-model="submitForm.result" placeholder="NORMAL / ABNORMAL"/></el-form-item><el-form-item label="备注"><el-input v-model="submitForm.remark" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="submitVisible=false">取消</el-button><el-button type="primary" @click="submitTask">提交</el-button></template></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { addInspectionPlan,pageInspectionPlans,pageInspectionTasks,updateInspectionPlanStatus,startInspectionTask,submitInspectionTask } from '../api/inspection';const active=ref('plans'),planLoading=ref(false),taskLoading=ref(false),plans=ref([]),tasks=ref([]),planTotal=ref(0),taskTotal=ref(0);const planQuery=reactive({pageNo:1,pageSize:10,planName:''});const taskQuery=reactive({pageNo:1,pageSize:10,planId:undefined});const planVisible=ref(false),submitVisible=ref(false);const planForm=reactive({planName:'',deviceId:1,inspectorId:1,cycleType:'DAILY',description:''});const submitForm=reactive({id:null,result:'',remark:''});async function loadPlans(){planLoading.value=true;try{const data=await pageInspectionPlans(planQuery);plans.value=data?.records||[];planTotal.value=data?.total||0}finally{planLoading.value=false}}async function loadTasks(){taskLoading.value=true;try{const params={...taskQuery};if(!params.planId)delete params.planId;const data=await pageInspectionTasks(params);tasks.value=data?.records||[];taskTotal.value=data?.total||0}finally{taskLoading.value=false}}function openPlan(){Object.assign(planForm,{planName:'',deviceId:1,inspectorId:1,cycleType:'DAILY',description:''});planVisible.value=true}async function savePlan(){await addInspectionPlan(planForm);ElMessage.success('创建成功');planVisible.value=false;loadPlans()}async function changePlanStatus(row,status){await updateInspectionPlanStatus(row.id,{status});ElMessage.success('状态已修改');loadPlans()}async function startTask(row){await startInspectionTask(row.id);ElMessage.success('已开始巡检');loadTasks()}function openSubmit(row){submitForm.id=row.id;submitForm.result='';submitForm.remark='';submitVisible.value=true}async function submitTask(){await submitInspectionTask(submitForm.id,{result:submitForm.result,remark:submitForm.remark});ElMessage.success('提交成功');submitVisible.value=false;loadTasks()}function taskStatusText(s){return {1:'待巡检',2:'巡检中',3:'已完成'}[Number(s)]||s}function taskStatusTag(s){return {1:'warning',2:'primary',3:'success'}[Number(s)]||'info'}onMounted(()=>{loadPlans();loadTasks()})</script>
